def isMultipleOf3(n):
    # base case
    if n == 0 or n == 1:
        return 1
    # case where n is negative
    if n < 0:
        return isMultipleOf3(-n)
    # initialize count of odd numbers and even numbers
    odd_count = 0
    even_count = 0
    # loop through all bits of n
    while n != 0:
        # count odd numbers
        if n & 1:
            odd_count += 1
        # count even numbers
        if n & 2:
            even_count += 1
        # shift n down by 2
        n >>= 2
    # call isMultipleOf3 on the difference of odd and even counts
    return isMultipleOf3(abs(odd_count - even_count))

